import { schemaTask, task } from "@trigger.dev/sdk/v3";
import { ai } from "@trigger.dev/sdk/v3";
import { z } from "zod";

const trial_id = process.env.TRIAL_ID || "123";

export const refineTask = schemaTask({
  id: `refine-text-${trial_id}`,
  schema: z.object({
    text: z.string(),
  }),
  run: async (payload) => {
    return payload.text + " (improved)";
  },
});

export const agentLoopTask = task({
  id: `agent-loop-${trial_id}`,
  run: async (payload: { text: string }) => {
    const tool = ai.tool(refineTask);

    let text = payload.text || "initial text";

    // Use the tool in a loop to refine at least twice
    for (let i = 0; i < 2; i++) {
      // Assuming tool can be called or passed to an AI model
      // We will mock calling the tool directly or triggering the task
      const result = await refineTask.triggerAndWait({ text });
      text = result.output as string;
    }

    return text;
  },
});

